using UnityEngine;

/// <summary>
/// Origem/tipo de um dano recebido pelo player. Usado por <see cref="DamageInfo"/>
/// e por sistemas de feedback/imunidade temporária (ex: "imune a Hazard por X
/// segundos depois de uma queda").
/// </summary>
public enum DamageType
{
    /// <summary>Ataque directo de um inimigo (corpo, garra, etc.).</summary>
    Enemy,

    /// <summary>Perigo do ambiente: espinhos, lava, armadilhas, etc.</summary>
    Hazard,

    /// <summary>Dano por queda de grande altura.</summary>
    Fall,

    /// <summary>Projéctil inimigo.</summary>
    Projectile,

    /// <summary>Explosão (ex: projéctil com "explosionDamage").</summary>
    Explosion,
}

/// <summary>
/// Pacote de informação sobre um dano recebido pelo player — substitui a lista
/// de parâmetros avulsos de <see cref="PlayerCombat.TryDamagePlayer"/> (P2 →
/// auditoria item 10). Permite estender o sistema de dano (tipo, imunidades
/// temporárias por tipo, resistência a knockback, feedback diferenciado) sem
/// voltar a mexer na assinatura do método.
/// </summary>
public struct DamageInfo
{
    /// <summary>Quantidade de dano antes de Defesa/Escudo (corações).</summary>
    public int Amount;

    /// <summary>Origem/tipo do dano — ver <see cref="DamageType"/>.</summary>
    public DamageType Type;

    /// <summary>Posição de onde o dano partiu (usada para calcular a direcção do knockback).</summary>
    public Vector2 SourcePosition;

    /// <summary>Força do knockback aplicado ao player (0 = sem empurrão).</summary>
    public float Knockback;

    /// <summary>Direcção explícita do knockback. Null = calculada a partir de SourcePosition.</summary>
    public Vector2? KnockbackDir;

    /// <summary>Se true, ignora a Defesa da forma actual e a Postura de Escudo (ex: dano de queda, hazards "puros").</summary>
    public bool IgnoreDefense;

    public DamageInfo(int amount, DamageType type, Vector2 sourcePosition, float knockback = 0f, Vector2? knockbackDir = null, bool ignoreDefense = false)
    {
        Amount = amount;
        Type = type;
        SourcePosition = sourcePosition;
        Knockback = knockback;
        KnockbackDir = knockbackDir;
        IgnoreDefense = ignoreDefense;
    }
}
